            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Maerin",
                text = "*(She keeps glaring, but the words pour out — the fury of someone who has had a great deal of time and no one worth saying it to.)* You want to know the worst part of dying Faithless? It isn't the *fading.* It's that the moment you're gone, everyone who *knew* you turns you into a *story about themselves.* My father — *(her voice cracks, hardens)* — my father will spend the rest of his life being *the man whose daughter the Wall took.* I'll be his *grief*, his *cause*, his *reason* to do brave sad things. And I won't be *Maerin* anymore. I'll be a *motivation.* *(she steps forward, flickering.)* I had *opinions*, Returned. I was *funny.* I was *unfair* to people who deserved it and *cruel* sometimes and I once made my father laugh so hard he fell off a *boat.* And all of that is about to get sanded down into *the dead girl who makes the living act.* *(fierce, fading.)* So when you go back up there — and you *will*, that's what your kind *does* — do *not* tell my father you met his *reason.* Tell him you met his *daughter*, who was *angry*, and *specific*, and *hers*, right up until the grey took the edges off.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 17] \"You're not afraid of fading. You're afraid of being *flattened* — of becoming a symbol so smooth no one remembers you had corners. So keep the corners. Be as unfair and funny and *specific* as you want. I'll carry the *girl*, not the cause.\"", nextNodeId = "corners", checkAbility = Ability.Wisdom, checkDC = 17, failNodeId = "snap" },
                    new DialogueChoice { text = "[PERSUADE 16] \"Then come back up *yourself* and be insufferable in person. You don't have to fade, Maerin. There's a road out of the niche — but it needs you *furious and alive*, not nobly gone.\"", nextNodeId = "recruit", checkAbility = Ability.Charisma, checkDC = 16, failNodeId = "bristle" },
