                    new DialogueChoice { text = "\"Your father fell off a boat. Tell me about *him* — not the grief he'll become. The man who laughed.\"", nextNodeId = "father", effects = new[] { new FlagClause { key = "companion.maerin.approval", op = FlagOp.AddInt, amount = 2 } } },
                }
