            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "A Light That Weeps",
                text = "*(Where the grey thins, a light hangs — not warm like Wickless, not cold like the Wall, but *luminous with sorrow*, a radiance that seems to weep without water, beautiful and almost unbearable to look at directly. As you approach it does not speak in words at first; it simply *brightens toward you*, testing, and you feel it reach into your chest to find out whether you are *carrying* anything it recognizes.)*",
