                onEnter = new[] { new FlagClause { key = "npc.mournlight_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "The Mournlight",
                text = "*(A voice arrives, made of many griefs layered into one chord.)* You may carry me. *(the light pulses.)* Or you may not. It is not your *strength* that decides it, Returned, nor your *will*, nor your *worthiness* in any way you could *earn.* I am the Mournlight — every grief for a Faithless soul that was *told it had no right to grieve.* The mother forbidden to mourn her doubting son. The widow whose husband was sorted to nothing while the priest said *do not weep, he chose it.* Ten thousand mournings that were *denied a place to land* — gathered, here, into light. *(it drifts closer.)* I can be *carried* to the Court of the Dead, where I would shine so that the gods *cannot look away* from the grief they forbade. But I will *only* let myself be lifted by hands that carry *real* grief — not performed, not borrowed, not strategic. *(gently, terribly.)* So I must look inside you. And you cannot *fake* what I'm looking for. Many have tried, with beautiful sad faces and nothing underneath, and I stayed where I am, and they walked on, lighter and emptier than they knew. Stand still. Let me see what you actually *mourn.*",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 18] \"Don't look for the *biggest* grief in me. Look for the one I've never let *land* — the one I'm not allowed to feel, the one I've been carrying *forbidden*, same as every soul you're made of. That's the one that matches you.\"", nextNodeId = "recognized", checkAbility = Ability.Wisdom, checkDC = 18, failNodeId = "hollow" },
                    new DialogueChoice { text = "\"*(stand still. Don't perform. Let it see the real one — the loss you've never spoken, the one with no permission)*\"", nextNodeId = "truegrief", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 3 } } },
                    new DialogueChoice { text = "\"I won't try to carry you if I'm carrying nothing true. Better you stay than be lifted by a lie that dims you.\"", nextNodeId = "honest", effects = new[] { new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } } },
                    new DialogueChoice { text = "[ARCANA 16] \"You're the golden-path key, aren't you. The Court can dismiss an *argument* about the Faithless. It cannot dismiss *light made of the grief it forbade.* You don't persuade the gods. You *indict* them, by shining.\"", nextNodeId = "indict", checkAbility = Ability.Intelligence, checkDC = 16, failNodeId = "hollow" },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "recognized", speaker = "The Mournlight",
                text = "*(The light *surges* — recognition, vast and immediate — and the weeping radiance wraps around you like something coming home.)* ...The one that never landed. *(the chord of voices trembles with relief.)* *Yes.* You *understand* me — not because you're sad, sadness is *common*, but because you carry a grief you were *forbidden to feel*, and that is the *precise* substance I am *made of.* *(the light settles into your hands, and it weighs nothing and everything.)* Every soul in me was *denied permission to mourn.* And you have, somewhere in you, a loss you've never been *allowed* to grieve — by circumstance, by duty, by a world that said *not now, not that one, not you.* *(it shines through your fingers.)* That forbidden grief is the *handle.* I fit it exactly. *(softly.)* Carry me to the Court, Returned. And when the gods say to the Faithless *you had no right to be mourned*, I will shine with ten thousand mournings that *happened anyway*, plus *yours*, and there is no doctrine in any heaven that can *un-see* a grief that bright. You found the handle by knowing you were *forbidden* too. That's why you, and not the beautiful liars. You didn't reach for me. You *recognized* me.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.mournlight_carried", op = FlagOp.SetTrue }, new FlagClause { key = "sq.carry_the_mournlight", op = FlagOp.SetTrue }, new FlagClause { key = "act2.golden_path_key", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "truegrief", speaker = "The Mournlight",
                text = "*(The light moves into you slowly, reading — and then it *weeps brighter*, and lifts toward your hands.)* Oh. *(quietly, the chord catching.)* There. That one. The one you've *never said out loud.* *(the radiance gathers.)* You didn't show me your *worst* grief — you showed me your *quietest* one, the loss you've kept folded so small no one ever saw you carry it. *(it settles, weightless, luminous.)* That's the truest thing you have, Returned: not the grand sorrows you've made peace with, but the small forbidden one still *raw* because it was never *allowed* to heal in the open. *(it shines.)* I can be carried by that. Only by that. *(gently.)* You held still and didn't perform, and so I *saw*, and what I saw was *real*, and now I am yours to bear to the place where grief becomes indictment. Thank you for not *trying* to deserve me. The ones who try are the ones who can't. You simply *stood there and ached*, and the ache was *true*, and true is the only key I take.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.mournlight_truegrief", op = FlagOp.SetTrue }, new FlagClause { key = "sq.carry_the_mournlight", op = FlagOp.SetTrue }, new FlagClause { key = "act2.golden_path_key", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "honest", speaker = "The Mournlight",
                text = "*(The light stills — and then warms, approving, even as it stays where it hangs.)* You will not lift me with a lie. *(the chord softens.)* Do you know, Returned, how *rare* that is? Everyone who passes *wants* me — I am power, I am the golden key, I am the thing that moves the gods — and almost all of them *reach*, certain that *wanting* me badly enough is the same as *grieving* truly. *(it pulses gently.)* You're the first in a long while to say: *not unless it's real.* *(the radiance brightens toward you, fond.)* And *that* — that integrity, that refusal to counterfeit a grief for advantage — *that* is so close to what I'm made of that you may find, if you stand a moment longer and stop *guarding* yourself, that you *do* carry something true after all. *(softly.)* Most people who are honest enough to refuse me are honest enough to *hold* me. Don't walk away yet. The fact that you wouldn't fake it is the surest sign you wouldn't *have* to.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.mournlight_honest", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "indict", speaker = "The Mournlight",
                text = "*(The light blazes — fierce now, the sorrow edged with something like wrath.)* *Indict.* *(the chord rings.)* You see it *exactly.* The gods have *answers* for arguments. They have *doctrine*, *precedent*, ten thousand years of *because-I-said-so* dressed as cosmic law. An argument they can *win.* *(the radiance intensifies.)* But I am not an argument. I am the *grief they forbade*, made *visible.* When I shine at the Court, I do not *say* the Faithless deserved mourning — I *am* the mourning, happening, undeniable, ten thousand mothers and widows and friends weeping in *light* the gods *told them not to shed.* *(softly, terribly.)* You cannot *refute* a tear. You can only *forbid* it — and I am every tear that was forbidden *and fell anyway.* *(it turns toward you.)* But to carry an indictment that bright, Returned, the hand must be *clean* — must carry *its own* forbidden grief, or I will read the lie and *gutter* at the threshold and you will stand before the gods holding *darkness.* *(gently.)* So. Do you grieve something you were never allowed to? Then lift me. And let us go make the heavens *look at what they refused to let anyone cry about.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.mournlight_indict", op = FlagOp.SetTrue }, new FlagClause { key = "sq.carry_the_mournlight", op = FlagOp.SetTrue }, new FlagClause { key = "act2.golden_path_key", op = FlagOp.SetTrue }, new FlagClause { key = "act2.wall_has_no_author", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "hollow", speaker = "The Mournlight",
                text = "*(The light dims — not unkindly, but with the weariness of a thing that has been *reached for* too often by the empty.)* No. *(the chord fades.)* What you showed me was *shaped* like grief, but there was *air* inside it — a sadness *performed*, or *borrowed*, or *aimed.* You wanted me for what I could *do*, not for what I *am.* *(it drifts back to its place in the thinning grey.)* I do not blame you. The forbidden grief is the *hardest* thing to find in oneself, precisely *because* it was forbidden — you may have buried yours so deep you no longer feel it, and called the numbness *fine.* *(gently.)* Come back when something has *broken open* in you. Not when you've *practiced* a sadder face. I cannot be carried by the face. Only by the *break.*)",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "The Mournlight",
                text = "*(The Mournlight hangs in the thinning grey — luminous with ten thousand forbidden sorrows, beautiful and unbearable, waiting for hands that carry a grief they were never allowed to feel — the one thing in all the afterlife that cannot be faked, borrowed, or argued with: a tear that fell anyway, made into light.)*",
            });

            NpcFugueMournlightDialogue = g;
        }

        private void BuildNpcFugueChoirDialogue()
        {
            var g = ScriptableObject.CreateInstance<DialogueGraph>();
            g.conversationId = "npc.fugue.choir";
            g.startNodeId = "0";

            g.nodes.Add(new DialogueNode
            {
                id = "0", speaker = "Three Voices in Harmony",
                text = "*(In the greyest reach, three shades stand close together — water still streaming from them though there is no water here, lungs that drowned still somehow *singing* — and the sound they make is the only beautiful thing you have heard in the whole plane of the dead: a low three-part harmony, wordless at first, then resolving, as you near, into *names.* They are singing *names*, one after another, an endless braided list, and they do not stop to greet you, because — you understand with a chill — they *cannot* stop.)*",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.choir_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Three Shades of a Drowned Choir",
                text = "*(One shade — the soprano, a girl with weed in her hair — manages to sing *to* you without breaking the list, weaving the words into the harmony so the names never cease.)* *We were a choir... on a ship called the Tern... and the Tern went down... and we kept singing... we did not know... how to do anything else.* *(the alto and bass carry the names beneath her.)* *And here in the grey... we found the names... the Faithless names... going out one by one... as the Wall takes them... and we found... that a name being* sung *is a name being* kept *... the Wall takes the carved and the written... but it cannot take the* sung *... for a song is not a thing you* have *... it is a thing you* do *... and a thing that is only ever* doing *can never be* filed.* *(her eyes find yours, desperate and luminous.)* *So we sing them. All of them. Eleven thousand. In harmony. And we cannot stop... because the moment we fall silent... the names we are holding aloft... go out.*",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 17] \"You've found the one thing the Wall can't take — a name that's only ever *being done*, never *kept.* But you've made yourselves a *second Wall*, haven't you? Eleven thousand names imprisoned in a song you can never end. There has to be a way to *set them down* without dropping them.\"", nextNodeId = "secondwall", checkAbility = Ability.Wisdom, checkDC = 17, failNodeId = "drown" },
                    new DialogueChoice { text = "[ARCANA 18] \"Teach me the harmony. If three voices can hold eleven thousand names, then thirty can hold them better, and three hundred better still — a *city* singing the Faithless can't be silenced by any god. Make me the fourth voice. Then I'll go make the fourth thousand.\"", nextNodeId = "teach", checkAbility = Ability.Intelligence, checkDC = 18, failNodeId = "drown" },
                    new DialogueChoice { text = "\"Sing me one. Just one name, lifted out of the braid, so I can carry that one *up* — out of the grey, into the warm, where it can be sung in daylight.\"", nextNodeId = "onename", effects = new[] { new FlagClause { key = "sq.choir_name", op = FlagOp.SetTrue }, new FlagClause { key = "companion.choir.approval", op = FlagOp.AddInt, amount = 3 } } },
                    new DialogueChoice { text = "\"Rest. Even for a breath. I'll hold the names while you do — I came back from the dead; I can hold a few names a moment. You've earned one silence.\"", nextNodeId = "rest", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 3 } } },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "secondwall", speaker = "Three Shades of a Drowned Choir",
                text = "*(The harmony *shudders* — all three shades faltering for a fraction of a beat before catching the braid again, and the soprano's eyes fill.)* *A second Wall.* *(she weaves it in, anguished.)* *You see it too. We have... saved them... into a* prison *... eleven thousand names... held safe... and held* hostage *... to three drowned throats that can never... ever... rest.* *(the bass groans the names lower, grieving.)* *We thought we were... their salvation... and we are only... their* better jailers. *(the soprano's voice breaks and mends.)* *But you say... set them down without dropping them. How? A name unsung... goes out. We have tried... falling silent one at a time... and each silence... is a soul lost.* *(then her eyes widen, the harmony swelling.)* *...Unless the song is* taught. *Unless it does not live... in three throats... but in* many. *A name sung by three... dies when the three tire. A name sung by a* thousand *... is sung even while a hundred sleep... for the song never... fully... stops.* *(luminous, desperate, hoping.)* *Is that it? Is that the way out of our beautiful prison? Not to sing* harder *... but to sing it* wider *... until no one... has to sing it... alone?*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.choir_second_wall", op = FlagOp.SetTrue }, new FlagClause { key = "sq.spread_the_song", op = FlagOp.SetTrue }, new FlagClause { key = "act2.cataloguing_defeats_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "companion.choir.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "teach", speaker = "Three Shades of a Drowned Choir",
                text = "*(All three shades turn toward you without breaking the braid, and something like *joy* enters the grief of the harmony.)* *The fourth voice.* *(the soprano lifts it.)* *Yes — oh, yes — come, stand, breathe with us... here is the first interval... the names rise on it... do you feel? You are holding... forty of them... already... just by* singing. *(the alto and bass open the harmony to make room for you.)* *We have wanted... for so long... a fourth... but the dead who pass... are too tired to sing... and the gods' servants... will not... and you are the first warm throat... in a hundred years... to ask for the* burden *instead of fleeing it.* *(the soprano's eyes blaze.)* *Take the harmony up into the warm world, Returned. Teach it. The candle-festival sings names for one night — but a* choir *sings them* always. *Make every griever a voice. Make the Faithless a song so* wide *the Wall cannot find its edges. We three held the line for as long as three could. Now... let the line become... a* people. *(the names soar.)* *Go. Be the fourth voice that becomes the four-thousandth.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.choir_teaches", op = FlagOp.SetTrue }, new FlagClause { key = "sq.spread_the_song", op = FlagOp.SetTrue }, new FlagClause { key = "act2.cataloguing_defeats_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.choir.approval", op = FlagOp.AddInt, amount = 5 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "onename", speaker = "Three Shades of a Drowned Choir",
                text = "*(The soprano nods, and with terrible care, she *lifts one name clear* of the braid — singing it high and alone for one shining moment while the alto and bass close the gap beneath so the list never breaks — and presses it, somehow, into your keeping.)* *Her name was... Sariel.* *(softly, the others holding the rest aloft.)* *A weaver. She doubted... in her last winter... cold and sick and reasonable... and the Wall took her for the doubting. We have sung her... for nine years... never once... in daylight.* *(the soprano's eyes shine.)* *Take Sariel up. Sing her... or only* say *her... where there is sun. Let one name... just one... be spoken in the warm world... after nine years in the grey. And when you do... we will feel the braid... grow one name* lighter *... not because we dropped her... but because* you took her up. *(the harmony swells, almost glad.)* *Sariel the weaver. Doubted, and was real. Carry her to the light. We will hold the other ten thousand... a little easier... knowing one of them... got out.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.choir_one_name", op = FlagOp.SetTrue }, new FlagClause { key = "sq.choir_name", op = FlagOp.SetTrue }, new FlagClause { key = "act2.sariel_carried", op = FlagOp.SetTrue }, new FlagClause { key = "companion.choir.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "rest", speaker = "Three Shades of a Drowned Choir",
                text = "*(The three shades go very still — and for one heartbeat, *two* of them fall silent, trusting you, while the soprano alone holds the thread and you find yourself — without deciding to — *humming* the names beneath her, catching the braid, holding it aloft with her so the alto and bass can, for the first time in nine years, simply *stand* and *breathe* and *not sing.*)* *(The bass, voiceless at last, weeps freely. The alto closes her eyes. And the soprano sings on, but lighter now, sharing the weight with a warm throat that came back from the dead to spell her.)* *...You held them.* *(she breathes between names.)* *You actually... held them. Strangers say* rest *and mean* stop. *You said rest and* took up the song. *(the rested shades open their eyes, changed.)* *Nine years. That is the first breath... we have drawn... in nine years. Thank you, Returned. Now we know... it* can *be shared. We will never... fear the silence... the same way again.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.choir_rested", op = FlagOp.SetTrue }, new FlagClause { key = "sq.spread_the_song", op = FlagOp.SetTrue }, new FlagClause { key = "act1.mercy_remembered", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "drown", speaker = "Three Shades of a Drowned Choir",
                text = "*(The harmony wavers — your words don't fit the meter, and to answer them the soprano would have to *stop*, and she cannot stop, and the grief of that is total.)* *We... cannot... answer that... without... falling... silent...* *(she sings it desperate and apologetic, the names straining.)* *...and if we fall silent... they go out... so please... do not ask us... to* explain *... ask us... to* sing *... it is the only thing... we have left... that is not... drowning.* *(the three voices close back into the braid, and the names go on, beautiful and unbroken and unable to rest, and you understand that some griefs cannot be spoken to — only sung beside.)*",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Three Shades of a Drowned Choir",
                text = "*(The drowned choir sings on in the greyest reach — three voices holding eleven thousand names aloft by never falling silent, the only beautiful thing in the plane of the unjudged dead — and you carry away the secret the Wall most fears: that a name being *sung* is a name being *kept*, that a song is the one thing that can never be *filed*, and that the way to defeat a Wall of the forgotten is not to break it but to make the whole world *sing.*)*",
            });

            NpcFugueChoirDialogue = g;
        }
    }
}
